+    fn unstack_axis0() {
+        // [[1,2],[3,4]] unstacked along axis=0 → [1,2] and [3,4]
+        let arr = UFuncArray::new(vec![2, 2], vec![1.0, 2.0, 3.0, 4.0], DType::F64).unwrap();
